#!/usr/bin/env python3
"""
sketch_knot_format.py — Rank-K exclusion-sketch wire format.

Phase A of the Standing-Wave Mesh rollout. See:
  - docs/STANDING_WAVE_MESH.md ("Sketch wire format" section)
  - docs/STANDING_WAVE_MESH_TODO.md (Phase A1/A2)

Why a sibling format and not just reuse GKQ v2:
  GKQ v2 (magic b"GKQ2") is consumed by the GkqBackend in fat-station and
  carries dense blocks + spectral blocks side by side. The sketches file is
  *only* spectral, has no dense fallback, and is meant to be consumed by
  cobordism / layer-worker code that already speaks KNOT (magic b"KNOT" +
  JSON metadata + concatenated tensor payload, see
  open-source/gnosis/distributed-inference/src/loader.rs lines 1-50).

Choosing KNOT magic + a new tensor `type` code ("SK32") means fat-station's
existing mmap/HTTP loader can list and range-fetch sketches with zero
loader-side changes; only the dequantizer needs to recognise "SK32" as a
rank-K spectral sketch (Phase B work — out of scope here).

Layout (mirrors gguf-to-knot.py):

  bytes 0..4   : b"KNOT"  magic
  bytes 4..6   : u16 LE version (= 1)
  bytes 6..10  : u32 LE meta_len
  bytes 10..10+meta_len : metadata JSON, UTF-8
  padding to 4-byte alignment
  1 byte codec marker (0x20 = fp32)
  tensor payload (concatenated, in metadata order)

Metadata JSON schema:

  {
    "name": "qwen-0.5b-sketches",
    "codec": "fp32",
    "topology": "rank-k-exclusion-sketch",
    "format_version": 1,
    "sketch_rank_default": 32,
    "config": {  // mirrors the source model's KnotConfig (informational)
      "hidden_dim": 896, "num_layers": 24, ...
    },
    "sketches": {
      "blk.0.attn_q.weight": {
        "offset": 0,
        "length": 12345,
        "type": "SK32",
        "d_out": 896, "d_in": 896, "rank": 32,
        "u_max": 0.123, "sigma_max": 4.56, "v_max": 0.789,
        "u_q8_len":  28672,   // d_out * rank
        "sigma_q8_len": 32,   // rank
        "v_q8_len":  28672    // rank * d_in
      },
      ...
    }
  }

Per-sketch payload layout (inside `payload[offset .. offset+length]`):

  bytes  0 .. u_q8_len                    : u_q8       (uint8, d_out × rank)
  bytes  u_q8_len .. u_q8_len + sigma_q8_len : sigma_q8 (uint8, rank)
  bytes  remaining                         : v_q8       (uint8, rank × d_in)

`u_q8` / `v_q8` are offset-128 signed-uint8 (q = round(x/max*127)+128, decode
`x = ((q-128)/127)*max`). `sigma_q8` is unsigned (q = round(x/max*255), decode
`x = (q/255)*max`). Identical to the encoding in
`encode-real-model.py:_spectral_quantize` and `gkq_v2_format.reconstruct_spectral`.

Sketches are NOT delta-encoded here. Delta-encoding inside GKQ v2 is a
storage micro-opt for the residual-by-rank case; sketches are tiny and
range-fetched on demand, so we keep the on-disk bytes verbatim so a HTTP
Range read returns a directly-usable q8 buffer.
"""

from __future__ import annotations

import json
import os
import shutil
import struct
import tempfile
import time
from typing import BinaryIO, Dict, List, Optional, Tuple

import numpy as np

MAGIC: bytes = b"KNOT"
VERSION: int = 1
CODEC_MARKER_FP32: int = 0x20
SKETCH_TYPE_CODE: str = "SK32"  # rank-K (≤32) spectral sketch
SKETCH_FORMAT_VERSION: int = 1


def _q8_signed(x: np.ndarray) -> Tuple[np.ndarray, float]:
    """Offset-128 signed-uint8 quantize. Returns (q8, x_max)."""
    x_max = float(np.abs(x).max() + 1e-10)
    q = np.clip(np.round((x / x_max) * 127.0) + 128.0, 0, 255).astype(np.uint8)
    return q, x_max


def _q8_unsigned(x: np.ndarray) -> Tuple[np.ndarray, float]:
    """Unsigned uint8 max-scaled quantize (used for sigma). Returns (q8, x_max)."""
    x_max = float(np.abs(x).max() + 1e-10)
    q = np.clip(np.round((x / x_max) * 255.0), 0, 255).astype(np.uint8)
    return q, x_max


def quantize_sketch(
    U: np.ndarray, sigma: np.ndarray, Vt: np.ndarray
) -> Tuple[np.ndarray, np.ndarray, np.ndarray, float, float, float]:
    """Quantize SVD factors using the same scheme as encode-real-model.py.

    U:  [d_out, rank] float32 (signed)
    sigma: [rank] float32 (non-negative)
    Vt: [rank, d_in] float32 (signed)

    Returns (u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max).
    """
    u_q8, u_max = _q8_signed(U)
    sigma_q8, sigma_max = _q8_unsigned(sigma)
    v_q8, v_max = _q8_signed(Vt)
    return u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max


def reconstruct_sketch(
    u_q8: np.ndarray, sigma_q8: np.ndarray, v_q8: np.ndarray,
    u_max: float, sigma_max: float, v_max: float,
) -> np.ndarray:
    """Inverse of quantize_sketch. Mirrors gkq_v2_format.reconstruct_spectral."""
    U = ((u_q8.astype(np.float32) - 128.0) / 127.0) * float(u_max)
    sigma = (sigma_q8.astype(np.float32) / 255.0) * float(sigma_max)
    Vt = ((v_q8.astype(np.float32) - 128.0) / 127.0) * float(v_max)
    return (U * sigma[np.newaxis, :]) @ Vt


# ─────────────────────────────────────────────────────────────────────────────
# WRITER
# ─────────────────────────────────────────────────────────────────────────────


class SketchEntry:
    __slots__ = (
        "name", "d_out", "d_in", "rank",
        "u_q8", "sigma_q8", "v_q8",
        "u_max", "sigma_max", "v_max",
    )

    def __init__(self, name: str, d_out: int, d_in: int, rank: int,
                 u_q8: np.ndarray, sigma_q8: np.ndarray, v_q8: np.ndarray,
                 u_max: float, sigma_max: float, v_max: float):
        self.name = name
        self.d_out = int(d_out)
        self.d_in = int(d_in)
        self.rank = int(rank)
        self.u_q8 = np.ascontiguousarray(u_q8, dtype=np.uint8)
        self.sigma_q8 = np.ascontiguousarray(sigma_q8, dtype=np.uint8)
        self.v_q8 = np.ascontiguousarray(v_q8, dtype=np.uint8)
        self.u_max = float(u_max)
        self.sigma_max = float(sigma_max)
        self.v_max = float(v_max)

    def payload_len(self) -> int:
        return self.u_q8.size + self.sigma_q8.size + self.v_q8.size

    def to_meta(self, offset: int) -> dict:
        return {
            "offset": int(offset),
            "length": int(self.payload_len()),
            "type": SKETCH_TYPE_CODE,
            "d_out": self.d_out,
            "d_in": self.d_in,
            "rank": self.rank,
            "u_max": self.u_max,
            "sigma_max": self.sigma_max,
            "v_max": self.v_max,
            "u_q8_len": int(self.u_q8.size),
            "sigma_q8_len": int(self.sigma_q8.size),
            "v_q8_len": int(self.v_q8.size),
        }


def write_sketches_knot(
    path: str,
    *,
    model_name: str,
    source_config: dict,
    sketches: List[SketchEntry],
    sketch_rank_default: int,
) -> dict:
    """Write a `<model>-sketches.knot` file. Returns a summary dict."""
    # Sort deterministically by name (stable mmap layout, easier diffs).
    sketches_sorted = sorted(sketches, key=lambda s: s.name)

    # First pass: assign sequential offsets, build metadata.
    cur_off = 0
    tensors_meta: Dict[str, dict] = {}
    for s in sketches_sorted:
        tensors_meta[s.name] = s.to_meta(cur_off)
        cur_off += s.payload_len()
    total_payload = cur_off

    metadata = {
        "name": model_name,
        "codec": "fp32",
        "topology": "rank-k-exclusion-sketch",
        "format_version": SKETCH_FORMAT_VERSION,
        "sketch_rank_default": int(sketch_rank_default),
        "config": source_config,
        "sketches": tensors_meta,
    }
    meta_bytes = json.dumps(metadata, separators=(",", ":"), sort_keys=True).encode("utf-8")
    meta_len = len(meta_bytes)
    # Fixed header (10 bytes) + meta_bytes, then pad to 4-byte boundary,
    # then 1 byte codec marker — exactly matches gguf-to-knot.py layout.
    payload_offset_pre_marker = (10 + meta_len + 3) & ~3
    pad_len = payload_offset_pre_marker - (10 + meta_len)

    with open(path, "wb") as f:
        f.write(MAGIC)
        f.write(struct.pack("<H", VERSION))
        f.write(struct.pack("<I", meta_len))
        f.write(meta_bytes)
        if pad_len:
            f.write(b"\x00" * pad_len)
        f.write(bytes([CODEC_MARKER_FP32]))
        # Tensor payload in metadata order (== sketches_sorted order).
        for s in sketches_sorted:
            f.write(s.u_q8.tobytes())
            f.write(s.sigma_q8.tobytes())
            f.write(s.v_q8.tobytes())

    import os
    file_size = os.path.getsize(path)
    return {
        "output_path": str(path),
        "num_sketches": len(sketches_sorted),
        "metadata_bytes": meta_len,
        "payload_bytes": total_payload,
        "file_size_bytes": file_size,
        "file_size_mb": file_size / 1e6,
        "sketch_rank_default": int(sketch_rank_default),
    }


class SpooledSketchesKnotWriter:
    """Disk-spooled sketch writer for 70B-class bundles.

    The regular writer needs every SketchEntry resident until the final KNOT
    header is known. That is fine for 0.5B/7B, but 70B-class rank-32 bundles
    approach a gigabyte. This helper writes each entry's payload to a temp file
    immediately, keeps only JSON-sized metadata in memory, then streams the
    payload into the final KNOT file.
    """

    def __init__(self, spool_dir: Optional[str] = None):
        self._spool_dir = spool_dir
        if spool_dir:
            os.makedirs(spool_dir, exist_ok=True)
        tmp = tempfile.NamedTemporaryFile(
            prefix="sketch-payload-",
            suffix=".bin",
            dir=spool_dir,
            delete=False,
        )
        self._payload_path = tmp.name
        self._payload_file = tmp
        self._cur_off = 0
        self._sketches: Dict[str, dict] = {}
        self._closed = False

    @property
    def payload_path(self) -> str:
        return self._payload_path

    @property
    def num_sketches(self) -> int:
        return len(self._sketches)

    @property
    def payload_bytes(self) -> int:
        return self._cur_off

    def add(self, sketch: SketchEntry) -> None:
        if self._closed:
            raise RuntimeError("cannot add sketches after writer is closed")
        if sketch.name in self._sketches:
            raise ValueError(f"duplicate sketch name: {sketch.name}")
        self._sketches[sketch.name] = sketch.to_meta(self._cur_off)
        self._payload_file.write(sketch.u_q8.tobytes())
        self._payload_file.write(sketch.sigma_q8.tobytes())
        self._payload_file.write(sketch.v_q8.tobytes())
        self._cur_off += sketch.payload_len()

    def write(
        self,
        path: str,
        *,
        model_name: str,
        source_config: dict,
        sketch_rank_default: int,
    ) -> dict:
        if self._closed:
            raise RuntimeError("cannot write after writer is closed")
        self._payload_file.flush()
        os.fsync(self._payload_file.fileno())
        self._payload_file.close()

        sketches_sorted = dict(sorted(self._sketches.items(), key=lambda item: item[0]))
        metadata = {
            "name": model_name,
            "codec": "fp32",
            "topology": "rank-k-exclusion-sketch",
            "format_version": SKETCH_FORMAT_VERSION,
            "sketch_rank_default": int(sketch_rank_default),
            "config": source_config,
            "sketches": sketches_sorted,
        }
        meta_bytes = json.dumps(metadata, separators=(",", ":"), sort_keys=True).encode("utf-8")
        meta_len = len(meta_bytes)
        payload_offset_pre_marker = (10 + meta_len + 3) & ~3
        pad_len = payload_offset_pre_marker - (10 + meta_len)

        with open(path, "wb") as out, open(self._payload_path, "rb") as payload:
            out.write(MAGIC)
            out.write(struct.pack("<H", VERSION))
            out.write(struct.pack("<I", meta_len))
            out.write(meta_bytes)
            if pad_len:
                out.write(b"\x00" * pad_len)
            out.write(bytes([CODEC_MARKER_FP32]))
            shutil.copyfileobj(payload, out, length=16 * 1024 * 1024)

        file_size = os.path.getsize(path)
        self.close()
        return {
            "output_path": str(path),
            "num_sketches": len(sketches_sorted),
            "metadata_bytes": meta_len,
            "payload_bytes": self._cur_off,
            "file_size_bytes": file_size,
            "file_size_mb": file_size / 1e6,
            "sketch_rank_default": int(sketch_rank_default),
        }

    def close(self) -> None:
        if self._closed:
            return
        try:
            if not self._payload_file.closed:
                self._payload_file.close()
        finally:
            try:
                os.unlink(self._payload_path)
            except FileNotFoundError:
                pass
            self._closed = True

    def __enter__(self) -> "SpooledSketchesKnotWriter":
        return self

    def __exit__(self, _exc_type, _exc, _tb) -> None:
        self.close()


# ─────────────────────────────────────────────────────────────────────────────
# READER
# ─────────────────────────────────────────────────────────────────────────────


def read_sketches_knot(path: str) -> dict:
    """Open a `<model>-sketches.knot` and return:
        {
          "metadata": <parsed JSON>,
          "payload_offset": int,                  # absolute offset of tensor payload
          "sketches": {name: SketchEntry, ...},   # all sketches dequantized into entries
        }
    """
    with open(path, "rb") as f:
        magic = f.read(4)
        if magic != MAGIC:
            raise ValueError(f"bad sketch magic: {magic!r} (expected {MAGIC!r})")
        (ver,) = struct.unpack("<H", f.read(2))
        if ver != VERSION:
            raise ValueError(f"unsupported sketch version: {ver}")
        (meta_len,) = struct.unpack("<I", f.read(4))
        metadata = json.loads(f.read(meta_len).decode("utf-8"))
        cur = 10 + meta_len
        pad_len = ((cur + 3) & ~3) - cur
        if pad_len:
            f.read(pad_len)
        codec_marker = f.read(1)[0]
        if codec_marker != CODEC_MARKER_FP32:
            raise ValueError(f"unexpected codec marker: {codec_marker:#x}")
        payload_offset = f.tell()

        sketches: Dict[str, SketchEntry] = {}
        for name, info in metadata.get("sketches", {}).items():
            f.seek(payload_offset + int(info["offset"]))
            d_out = int(info["d_out"])
            d_in = int(info["d_in"])
            rank = int(info["rank"])
            u_len = int(info["u_q8_len"])
            s_len = int(info["sigma_q8_len"])
            v_len = int(info["v_q8_len"])
            u_q8 = np.frombuffer(f.read(u_len), dtype=np.uint8).reshape(d_out, rank).copy()
            sigma_q8 = np.frombuffer(f.read(s_len), dtype=np.uint8).copy()
            v_q8 = np.frombuffer(f.read(v_len), dtype=np.uint8).reshape(rank, d_in).copy()
            sketches[name] = SketchEntry(
                name=name, d_out=d_out, d_in=d_in, rank=rank,
                u_q8=u_q8, sigma_q8=sigma_q8, v_q8=v_q8,
                u_max=float(info["u_max"]),
                sigma_max=float(info["sigma_max"]),
                v_max=float(info["v_max"]),
            )

    return {
        "metadata": metadata,
        "payload_offset": payload_offset,
        "sketches": sketches,
    }


# ─────────────────────────────────────────────────────────────────────────────
# SMOKE TEST
# ─────────────────────────────────────────────────────────────────────────────


def _smoke_test() -> None:
    import tempfile
    import os
    rng = np.random.default_rng(0)
    rank = 8
    d_out, d_in = 16, 24
    # Fabricate plausible SVD factors.
    U = rng.standard_normal((d_out, rank)).astype(np.float32) * 0.1
    sigma = np.abs(rng.standard_normal(rank).astype(np.float32))
    Vt = rng.standard_normal((rank, d_in)).astype(np.float32) * 0.1

    u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max = quantize_sketch(U, sigma, Vt)
    entry = SketchEntry("blk.0.attn_q.weight", d_out, d_in, rank,
                        u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max)
    entry2 = SketchEntry("output.weight", d_out, d_in, rank,
                         u_q8.copy(), sigma_q8.copy(), v_q8.copy(),
                         u_max, sigma_max, v_max)

    with tempfile.NamedTemporaryFile(suffix=".knot", delete=False) as tf:
        tmp_path = tf.name
    try:
        summary = write_sketches_knot(
            tmp_path,
            model_name="smoke-sketch",
            source_config={"hidden_dim": d_in, "num_layers": 1},
            sketches=[entry, entry2],
            sketch_rank_default=rank,
        )
        assert summary["num_sketches"] == 2
        loaded = read_sketches_knot(tmp_path)
        assert "blk.0.attn_q.weight" in loaded["sketches"]
        assert "output.weight" in loaded["sketches"]
        rt = loaded["sketches"]["blk.0.attn_q.weight"]
        assert rt.d_out == d_out and rt.d_in == d_in and rt.rank == rank
        assert np.array_equal(rt.u_q8, u_q8)
        assert np.array_equal(rt.sigma_q8, sigma_q8)
        assert np.array_equal(rt.v_q8, v_q8)
        # Reconstruction matches the original UΣV^T to within quantization.
        W_orig = (U * sigma[np.newaxis, :]) @ Vt
        W_rec = reconstruct_sketch(rt.u_q8, rt.sigma_q8, rt.v_q8,
                                   rt.u_max, rt.sigma_max, rt.v_max)
        err = float(np.linalg.norm(W_orig - W_rec) / (np.linalg.norm(W_orig) + 1e-12))
        assert err < 0.05, f"reconstruction error too high: {err}"
        print(f"sketch_knot_format: smoke test PASSED (rel-err {err:.4f})")
    finally:
        os.unlink(tmp_path)


if __name__ == "__main__":
    _smoke_test()
